/**
 * Per-entity integration **assembly module** + surface **tokens** emitter
 * (RFC-0002 §2/§4, Track D · E2).
 *
 * Per (surface, provider, entity-with-`surface:` + `pattern: Integrated`), emits
 * the TEXT of:
 *
 *   src/integrations/<surface>/
 *     modules/<provider>/<entity>-integration.module.ts   @generated — the assembly
 *     <surface>-integration.tokens.ts                      @generated — all surface tokens
 *
 * (the per-entity `<entity>.sink.ts` scaffold is emitted by the sibling
 * `sink-emission-generator.ts`; the surface-level integration *aggregator*
 * — `<surface>-integration.module.ts` — is E3, NOT emitted here.)
 *
 * ## Option A (RFC-0002 §3, RATIFIED) — bind the change source from the adapter
 *
 * The assembly binds `INTEGRATION_CHANGE_SOURCE = adapter.changeSources['<entity>']`
 * (the source is constructed once, inside the adapter's `changeSources`
 * container — RFC-0001's read-side seam) rather than re-constructing it via a
 * free factory. This keeps the orchestrator's single-source DI model and is the
 * faithful generated form of swe-brain's proven `*-integration.module.ts`. The
 * only imports the assembly carries are the entity module + the adapter module
 * (post-E0 the adapter is standalone-importable — no surface-aggregator edge).
 *
 * ## Pure emitter
 *
 * This file is the *pure string-builder* only — paths + names arrive as params.
 * The caller (`emitAdapters` in `adapter-emission-generator.ts`) resolves the
 * entity repo/module import specifiers from the locations config and owns all
 * filesystem wiring.
 */

import { relative, resolve, sep } from "node:path";
import { providerConstantCase, providerPascalCase } from "./provider-module-generator";

// ============================================================================
// Banner
// ============================================================================

function generatedBanner(sourceDesc: string): string {
  return (
    `// @generated by @pattern-stack/codegen from ${sourceDesc} — DO NOT EDIT.\n` +
    `// Hand edits are overwritten on re-emit. Regenerate with \`bun run codegen\`.`
  );
}

// ============================================================================
// Names
// ============================================================================

/** Entity names are snake_case (`call_recording`); provider slugs are kebab
 *  (`ms-graph`). The provider helpers split on `-` only, so entity names need a
 *  `_`-aware PascalCase/CONSTANT_CASE transform (matching clean-lite-ps'
 *  `pascalCase`). e.g. `call_recording` → `CallRecording` / `CALL_RECORDING`. */
function entityPascalCase(name: string): string {
  return name
    .split("_")
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join("");
}

function entityConstantCase(name: string): string {
  return name.replace(/-/g, "_").toUpperCase();
}

/** Token const name for an (entity, provider) use-case handle. e.g.
 *  entity `meeting`, provider `google` → `MEETING_INTEGRATION_USE_CASE__GOOGLE`. */
export function integrationUseCaseToken(entityName: string, providerSlug: string): string {
  return `${entityConstantCase(entityName)}_INTEGRATION_USE_CASE__${providerConstantCase(providerSlug)}`;
}

/** Module class name for an (entity, provider) assembly. e.g.
 *  entity `meeting`, provider `google` → `MeetingIntegrationModule__Google`. */
export function assemblyModuleClass(entityName: string, providerSlug: string): string {
  return `${entityPascalCase(entityName)}IntegrationModule__${providerPascalCase(providerSlug)}`;
}

/** The `Symbol.for(...)` key for an (entity, provider) use-case token. Mirrors
 *  the `generateSurfaceTokens` convention (`@app/integrations/<surface>.<name>`). */
function tokenSymbolKey(surface: string, entityName: string, providerSlug: string): string {
  return `@app/integrations/${surface}.${entityName}-integration-use-case.${providerSlug}`;
}

// ============================================================================
// Inputs
// ============================================================================

/** Pure input for {@link generateAssemblyModule}. The caller derives the import
 *  specifiers from the locations config; nothing here is path-computed inside
 *  the emitter. */
export interface AssemblyEmitInput {
  /** Surface tag (`calendar`). Drives the relative adapter import paths + banner. */
  surface: string;
  /** Bare provider slug (`google`). */
  provider: string;
  /** Entity name, snake_case singular (`meeting`). */
  entityName: string;
  /** PascalCase entity class (`Meeting`). Drives the sink + repo + module names. */
  entityClass: string;
  /** Module specifier for the entity's generated NestJS module
   *  (`@modules/meetings/meetings.module` or a relative fallback). Caller-computed. */
  moduleImportSpecifier: string;
  /** Class name of the entity's generated NestJS module (`MeetingsModule`). */
  moduleClass: string;
  /** Module specifier for the entity's generated repository
   *  (`@modules/meetings/meeting.repository` or a relative fallback). Caller-computed. */
  repoImportSpecifier: string;
  /** Class name of the entity's generated repository (`MeetingRepository`). */
  repoClass: string;
  /** Source descriptor for the @generated banner (the provider YAML path). */
  sourceDesc: string;
}

/** One (entity, provider) token entry on a surface, for {@link generateIntegrationTokens}. */
export interface IntegrationTokenEntry {
  entityName: string;
  entityClass: string;
  provider: string;
}

// ============================================================================
// Emitters
// ============================================================================

/**
 * Emit the @generated per-entity assembly module (Option A). Imports the entity
 * module + the adapter module; binds `INTEGRATION_CHANGE_SOURCE` from
 * `adapter.changeSources['<entity>']` and `INTEGRATION_SINK` from a new
 * `<Entity>Sink(repo, '<provider>')`; provides a local `ExecuteIntegrationUseCase`
 * and aliases+exports it under the unique `<ENTITY>_INTEGRATION_USE_CASE__<PROVIDER>`.
 */
export function generateAssemblyModule(input: AssemblyEmitInput): string {
  const providerPascal = providerPascalCase(input.provider);
  const surfacePascal = providerPascalCase(input.surface);

  // Adapter class + module — mirror `names()` in adapter-emission-generator.ts.
  const adapterClass = `${providerPascal}${surfacePascal}Adapter`;
  const adapterModuleClass = `${adapterClass}Module`;
  // Adapter files live at `../../adapters/<provider>/<provider>-<surface>.adapter[.module]`
  // relative to `<surface>/modules/<provider>/`.
  const adapterImport = `../../adapters/${input.provider}/${input.provider}-${input.surface}.adapter`;
  const adapterModuleImport = `${adapterImport}.module`;

  const sinkClass = `${input.entityClass}Sink`;
  // The sink scaffold lives at `../../sinks/<entity>.sink` relative to the module.
  const sinkImport = `../../sinks/${input.entityName}.sink`;

  const token = integrationUseCaseToken(input.entityName, input.provider);
  const moduleClass = assemblyModuleClass(input.entityName, input.provider);
  // The tokens file is the surface-level `<surface>-integration.tokens`, one dir
  // up from `modules/<provider>/`.
  const tokensImport = `../../${input.surface}-integration.tokens`;

  return `${generatedBanner(input.sourceDesc)}
import { Module } from '@nestjs/common';
import {
  ExecuteIntegrationUseCase,
  INTEGRATION_CHANGE_SOURCE,
  INTEGRATION_SINK,
} from '@pattern-stack/codegen/subsystems';
import { ${adapterClass} } from '${adapterImport}';
import { ${adapterModuleClass} } from '${adapterModuleImport}';
import { ${sinkClass} } from '${sinkImport}';
import { ${input.repoClass} } from '${input.repoImportSpecifier}';
import { ${input.moduleClass} } from '${input.moduleImportSpecifier}';
import { ${token} } from '${tokensImport}';

/**
 * ${moduleClass} — the ${input.surface}/${input.entityName} ← ${input.provider}
 * inbound-integration assembly (RFC-0002 §2, Option A).
 *
 * Binds this module's INTEGRATION_CHANGE_SOURCE from the adapter's
 * \`changeSources['${input.entityName}']\` and INTEGRATION_SINK from
 * ${sinkClass}, provides a local ExecuteIntegrationUseCase, and aliases+exports
 * it under ${token} (the bare class token is ambiguous at app root — every
 * assembly provides it). The substrate (cursor store, run recorder, differ,
 * multi-tenant flag) comes from the global IntegrationModule.forRoot(...) in
 * AppModule, never re-bound here.
 */
@Module({
  imports: [${input.moduleClass}, ${adapterModuleClass}],
  providers: [
    {
      provide: INTEGRATION_CHANGE_SOURCE,
      useFactory: (adapter: ${adapterClass}) => adapter.changeSources['${input.entityName}'],
      inject: [${adapterClass}],
    },
    {
      provide: INTEGRATION_SINK,
      useFactory: (repo: ${input.repoClass}) => new ${sinkClass}(repo, '${input.provider}'),
      inject: [${input.repoClass}],
    },
    ExecuteIntegrationUseCase,
    { provide: ${token}, useExisting: ExecuteIntegrationUseCase },
  ],
  exports: [${token}],
})
export class ${moduleClass} {}
`;
}

/**
 * Emit the @generated surface integration tokens file — one
 * `<ENTITY>_INTEGRATION_USE_CASE__<PROVIDER>` Symbol per (entity, provider) on
 * the surface. The token is a `Symbol.for(...)` (a valid NestJS `provide:`
 * token) the consuming trigger grabs to run the integration.
 */
export function generateIntegrationTokens(
  surface: string,
  entries: IntegrationTokenEntry[],
): string {
  // Deterministic order: by entity, then provider.
  const sorted = [...entries].sort((a, b) =>
    a.entityName === b.entityName
      ? a.provider < b.provider
        ? -1
        : 1
      : a.entityName < b.entityName
        ? -1
        : 1,
  );

  const tokenLines = sorted
    .map((e) => {
      const token = integrationUseCaseToken(e.entityName, e.provider);
      const key = tokenSymbolKey(surface, e.entityName, e.provider);
      return (
        `/** Unique handle for the ${e.entityName} ← ${e.provider} integration use-case\n` +
        ` *  (${assemblyModuleClass(e.entityName, e.provider)}). A trigger grabs this to run it. */\n` +
        `export const ${token} = Symbol.for('${key}');`
      );
    })
    .join("\n\n");

  return `${generatedBanner(`surface: ${surface}`)}
/**
 * Use-case handles for the \`${surface}\` surface — one per (entity, provider)
 * assembly. Each is a Symbol \`provide:\` token a per-entity
 * \`ExecuteIntegrationUseCase\` is aliased under (the bare class token is
 * ambiguous at app root) and exported for the consuming trigger to grab.
 */

${tokenLines || "// no (entity, provider) integration assemblies on this surface yet"}
`;
}

// ============================================================================
// Import-path resolution (RFC-0002 §2 — the entity repo + module imports)
// ============================================================================

/**
 * Where the clean-lite-ps pipeline emits an entity's repository + NestJS module,
 * and how to import them from the assembly file.
 *
 * Mirrors `buildCleanLitePsLocals` (templates/.../clean-lite-ps/prompt-extension.js):
 *   - repo:   `<backend_src>/modules[/<context>]/<plural>/<entity>.repository.ts`
 *   - module: `<backend_src>/modules[/<context>]/<plural>/<plural>.module.ts`
 *
 * The assembly file lives at
 *   `<backend_src>/integrations/<surface>/modules/<provider>/<entity>-integration.module.ts`.
 *
 * Import strategy (matches swe-brain's proven `@modules/...` form): prefer a
 * tsconfig **path alias** whose target dir contains the entity's module folder
 * (e.g. `@modules` → `<backend_src>/modules` ⇒ `@modules/meetings/meeting.repository`);
 * fall back to a correct **relative path** when no alias matches.
 */
export interface EntityModuleLocation {
  /** PascalCase entity class (`Meeting`). */
  entityClass: string;
  /** `<Entity>Repository` class name (`MeetingRepository`). */
  repoClass: string;
  /** `<PluralPascal>Module` class name (`MeetingsModule`). */
  moduleClass: string;
  /** Import specifier for the repo (alias or relative, no extension). */
  repoImportSpecifier: string;
  /** Import specifier for the module (alias or relative, no extension). */
  moduleImportSpecifier: string;
}

export interface ResolveEntityModuleImportsInput {
  /** Entity name, snake_case singular (`meeting`). */
  entityName: string;
  /** Entity plural (`meetings`). Defaults to a naive `+s` only as a last resort. */
  entityPlural: string;
  /** Bounded-context segment (`entity.context`) or null — nests the module folder. */
  context: string | null;
  /** Surface tag (`calendar`) — locates the assembly file. */
  surface: string;
  /** Provider slug (`google`) — locates the assembly file. */
  provider: string;
  /** Absolute `<backend_src>` root on disk (e.g. `/abs/project/src`). */
  backendSrcAbs: string;
  /** tsconfig path aliases: aliasKey → absolute target dir. May be empty. */
  aliases: Record<string, string>;
}

/** PascalCase a plural for the module class (`meetings` → `Meetings`). */
function pluralPascalCase(plural: string): string {
  return plural
    .split("_")
    .filter(Boolean)
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
    .join("");
}

/** Express an absolute target file (no extension) as an alias import if any
 *  alias target dir is a prefix, else as a relative import from `fromDirAbs`.
 *  Always emits POSIX separators and strips the `.ts` extension. */
function toImportSpecifier(
  targetFileAbs: string,
  fromDirAbs: string,
  aliases: Record<string, string>,
): string {
  const noExt = targetFileAbs.replace(/\.ts$/, "");
  // Prefer the longest-matching alias (most specific wins).
  let best: { key: string; rest: string } | null = null;
  for (const [key, dirRaw] of Object.entries(aliases)) {
    const dir = dirRaw.endsWith(sep) ? dirRaw.slice(0, -1) : dirRaw;
    const prefix = dir + sep;
    if (noExt === dir || noExt.startsWith(prefix)) {
      const rest = noExt === dir ? "" : noExt.slice(prefix.length);
      if (!best || dir.length > aliases[best.key].length) {
        best = { key, rest };
      }
    }
  }
  if (best) {
    const restPosix = best.rest.split(sep).join("/");
    return restPosix ? `${best.key}/${restPosix}` : best.key;
  }
  // Relative fallback.
  let rel = relative(fromDirAbs, noExt).split(sep).join("/");
  if (!rel.startsWith(".")) rel = `./${rel}`;
  return rel;
}

/**
 * Resolve the entity's repo + module class names + import specifiers for the
 * assembly. Pure: all filesystem inputs (the `<backend_src>` root, the aliases)
 * are passed in; nothing is read from disk here.
 */
export function resolveEntityModuleImports(
  input: ResolveEntityModuleImportsInput,
): EntityModuleLocation {
  const entityClass = entityPascalCase(input.entityName);
  const repoClass = `${entityClass}Repository`;
  const moduleClass = `${pluralPascalCase(input.entityPlural)}Module`;

  // clean-lite-ps module-folder base: `<backend_src>/modules[/<context>]/<plural>`.
  const moduleGroupSegs = input.context
    ? ["modules", input.context, input.entityPlural]
    : ["modules", input.entityPlural];
  const repoFileAbs = resolve(
    input.backendSrcAbs,
    ...moduleGroupSegs,
    `${input.entityName}.repository.ts`,
  );
  const moduleFileAbs = resolve(
    input.backendSrcAbs,
    ...moduleGroupSegs,
    `${input.entityPlural}.module.ts`,
  );

  // The assembly file's directory: `<backend_src>/integrations/<surface>/modules/<provider>`.
  const assemblyDirAbs = resolve(
    input.backendSrcAbs,
    "integrations",
    input.surface,
    "modules",
    input.provider,
  );

  return {
    entityClass,
    repoClass,
    moduleClass,
    repoImportSpecifier: toImportSpecifier(repoFileAbs, assemblyDirAbs, input.aliases),
    moduleImportSpecifier: toImportSpecifier(moduleFileAbs, assemblyDirAbs, input.aliases),
  };
}
